import{_ as t,c as a,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const h=JSON.parse(`{"title":"Quota OpenAI : Limites 3h et 24h | opencode-mystatus","description":"Apprenez à consulter les quotas OpenAI 3h/24h avec mystatus. Interprétez la barre de progression, le temps de réinitialisation et gérez l'expiration du jeton OAuth.","frontmatter":{"title":"Quota OpenAI : Limites 3h et 24h | opencode-mystatus","sidebarTitle":"Quota OpenAI","subtitle":"Consultation des quotas OpenAI : limites de 3 heures et 24 heures","description":"Apprenez à consulter les quotas OpenAI 3h/24h avec mystatus. Interprétez la barre de progression, le temps de réinitialisation et gérez l'expiration du jeton OAuth.","tags":["OpenAI","Consultation des quotas","Quota API"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"fr/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"fr/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}`),o={name:"fr/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function r(s,e,l,p,d,u){return n(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="consultation-des-quotas-openai-limites-de-3-heures-et-24-heures" tabindex="-1">Consultation des quotas OpenAI : limites de 3 heures et 24 heures <a class="header-anchor" href="#consultation-des-quotas-openai-limites-de-3-heures-et-24-heures" aria-label="Permalink to &quot;Consultation des quotas OpenAI : limites de 3 heures et 24 heures&quot;">​</a></h1><h2 id="ce-que-vous-saurez-faire-a-la-fin" tabindex="-1">Ce que vous saurez faire à la fin <a class="header-anchor" href="#ce-que-vous-saurez-faire-a-la-fin" aria-label="Permalink to &quot;Ce que vous saurez faire à la fin&quot;">​</a></h2><ul><li>Utiliser <code>/mystatus</code> pour consulter les quotas des abonnements OpenAI Plus/Team/Pro</li><li>Comprendre les informations de limite de 3 heures et 24 heures dans la sortie</li><li>Comprendre les différences entre fenêtre principale et fenêtre secondaire</li><li>Comprendre la gestion en cas d&#39;expiration de jeton</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><p>Les appels API d&#39;OpenAI ont des limites, et les dépassements entraînent une restriction temporaire d&#39;accès. Mais vous ne savez pas :</p><ul><li>Combien de quota reste-t-il actuellement ?</li><li>Quelle fenêtre de 3h ou 24h est utilisée ?</li><li>Quand se réinitialise-t-elle ?</li><li>Pourquoi voyez-vous parfois les données de deux fenêtres ?</li></ul><p>Si vous ne maîtrisez pas ces informations à temps, cela pourrait affecter votre progression d&#39;utilisation de ChatGPT pour écrire du code ou faire des projets.</p><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand utiliser cette méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand utiliser cette méthode&quot;">​</a></h2><p>Quand vous :</p><ul><li>Besoin d&#39;utiliser fréquemment l&#39;API OpenAI pour le développement</li><li>Remarquez que les réponses sont plus lentes ou que la limitation de débit s&#39;active</li><li>Voulez comprendre l&#39;utilisation du compte d&#39;équipe</li><li>Voulez savoir quand le quota sera renouvelé</li></ul><h2 id="approche-principale" tabindex="-1">Approche principale <a class="header-anchor" href="#approche-principale" aria-label="Permalink to &quot;Approche principale&quot;">​</a></h2><p>OpenAI a deux fenêtres de limitation de débit pour les appels API :</p><table tabindex="0"><thead><tr><th>Type de fenêtre</th><th>Durée</th><th>Rôle</th></tr></thead><tbody><tr><td><strong>Fenêtre principale</strong> (primary)</td><td>Renvoyée par le serveur OpenAI</td><td>Empêcher un grand nombre d&#39;appels en peu de temps</td></tr><tr><td><strong>Fenêtre secondaire</strong> (secondary)</td><td>Renvoyée par le serveur OpenAI (peut ne pas exister)</td><td>Empêcher une utilisation excessive à long terme</td></tr></tbody></table><p>mystatus interroge ces deux fenêtres en parallèle et affiche chacune :</p><ul><li>Pourcentage d&#39;utilisation</li><li>Barre de progression du quota restant</li><li>Temps restant jusqu&#39;à la réinitialisation</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>La durée de la fenêtre est renvoyée par le serveur OpenAI, et peut varier selon le type d&#39;abonnement (Plus, Team, Pro).</p></div><h2 id="suivez-les-etapes" tabindex="-1">Suivez les étapes <a class="header-anchor" href="#suivez-les-etapes" aria-label="Permalink to &quot;Suivez les étapes&quot;">​</a></h2><h3 id="etape-1-executer-la-commande-de-consultation" tabindex="-1">Étape 1 : Exécuter la commande de consultation <a class="header-anchor" href="#etape-1-executer-la-commande-de-consultation" aria-label="Permalink to &quot;Étape 1 : Exécuter la commande de consultation&quot;">​</a></h3><p>Dans OpenCode, entrez <code>/mystatus</code>, le système interrogera automatiquement les quotas de toutes les plateformes configurées.</p><p><strong>Ce que vous devriez voir</strong> : Contient les informations de quota de toutes les plateformes configurées (OpenAI, Zhipu AI, Z.ai, Copilot, Google Cloud, etc., selon les plateformes que vous avez configurées).</p><h3 id="etape-2-trouver-la-section-openai" tabindex="-1">Étape 2 : Trouver la section OpenAI <a class="header-anchor" href="#etape-2-trouver-la-section-openai" aria-label="Permalink to &quot;Étape 2 : Trouver la section OpenAI&quot;">​</a></h3><p>Dans la sortie, trouvez la section <code>## OpenAI Account Quota</code>.</p><p><strong>Ce que vous devriez voir</strong> : Un contenu similaire à celui-ci :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>███████████████░░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="etape-3-interpreter-les-informations-de-fenetre-principale" tabindex="-1">Étape 3 : Interpréter les informations de fenêtre principale <a class="header-anchor" href="#etape-3-interpreter-les-informations-de-fenetre-principale" aria-label="Permalink to &quot;Étape 3 : Interpréter les informations de fenêtre principale&quot;">​</a></h3><p>La <strong>fenêtre principale</strong> (primary_window) affiche généralement :</p><ul><li><strong>Nom de la fenêtre</strong> : par exemple <code>3-hour limit</code> ou <code>24-hour limit</code></li><li><strong>Barre de progression</strong> : Affichage visuel de la proportion du quota restant</li><li><strong>Pourcentage restant</strong> : par exemple <code>60% remaining</code></li><li><strong>Temps de réinitialisation</strong> : par exemple <code>Resets in: 2h 30m</code></li></ul><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Le nom de la fenêtre affiche la durée (3 heures / 24 heures)</li><li>Plus la barre de progression est pleine, plus le reste est important ; plus elle est vide, plus elle sera bientôt épuisée</li><li>Le temps de réinitialisation est un compte à rebours ; quand il atteint zéro, le quota est renouvelé</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>Si vous voyez le message <code>Limit reached!</code>, cela signifie que le quota de la fenêtre actuelle est épuisé, vous devez attendre la réinitialisation.</p></div><h3 id="etape-4-consulter-la-fenetre-secondaire-si-elle-existe" tabindex="-1">Étape 4 : Consulter la fenêtre secondaire (si elle existe) <a class="header-anchor" href="#etape-4-consulter-la-fenetre-secondaire-si-elle-existe" aria-label="Permalink to &quot;Étape 4 : Consulter la fenêtre secondaire (si elle existe)&quot;">​</a></h3><p>Si OpenAI renvoie des données de fenêtre secondaire, vous verrez :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>████████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>La fenêtre secondaire affiche un autre quota temporel (généralement 24 heures)</li><li>Peut avoir un pourcentage restant différent de la fenêtre principale</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>La fenêtre secondaire est un pool de quota indépendant ; l&#39;épuisement de la fenêtre principale n&#39;affecte pas la fenêtre secondaire, et inversement.</p></div><h3 id="etape-5-consulter-le-type-d-abonnement" tabindex="-1">Étape 5 : Consulter le type d&#39;abonnement <a class="header-anchor" href="#etape-5-consulter-le-type-d-abonnement" aria-label="Permalink to &quot;Étape 5 : Consulter le type d&#39;abonnement&quot;">​</a></h3><p>Dans la ligne <code>Account</code>, vous pouvez voir le type d&#39;abonnement :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   Type d&#39;abonnement</span></span></code></pre></div><p><strong>Types d&#39;abonnement courants</strong> :</p><ul><li><code>plus</code> : Abonnement personnel Plus</li><li><code>team</code> : Abonnement équipe/organisation</li><li><code>pro</code> : Abonnement Pro</li></ul><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Votre type de compte s&#39;affiche entre parenthèses après l&#39;email</li><li>Différents types peuvent avoir des limites différentes</li></ul><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Vérifiez votre compréhension :</p><table tabindex="0"><thead><tr><th>Scénario</th><th>Ce que vous devriez voir</th></tr></thead><tbody><tr><td>Fenêtre principale reste 60%</td><td>Barre de progression environ 60% pleine, affichage <code>60% remaining</code></td></tr><tr><td>Réinitialisation dans 2,5 heures</td><td>Affichage <code>Resets in: 2h 30m</code></td></tr><tr><td>Limite atteinte</td><td>Affichage <code>Limit reached!</code></td></tr><tr><td>Fenêtre secondaire présente</td><td>Fenêtre principale et secondaire affichent chacune une ligne de données</td></tr></tbody></table><h2 id="pieges-a-eviter" tabindex="-1">Pièges à éviter <a class="header-anchor" href="#pieges-a-eviter" aria-label="Permalink to &quot;Pièges à éviter&quot;">​</a></h2><h3 id="❌-operation-incorrecte-ne-pas-rafraichir-apres-expiration-du-jeton" tabindex="-1">❌ Opération incorrecte : Ne pas rafraîchir après expiration du jeton <a class="header-anchor" href="#❌-operation-incorrecte-ne-pas-rafraichir-apres-expiration-du-jeton" aria-label="Permalink to &quot;❌ Opération incorrecte : Ne pas rafraîchir après expiration du jeton&quot;">​</a></h3><p><strong>Symptôme</strong> : Vous voyez le message <code>⚠️ OAuth 授权已过期</code> (chinois) ou <code>⚠️ OAuth token expired</code> (anglais)</p><p><strong>Cause</strong> : Le jeton OAuth a expiré (durée spécifique contrôlée par le serveur), et il est impossible de consulter le quota après expiration.</p><p><strong>Opération correcte</strong> :</p><ol><li>Reconnectez-vous à OpenAI dans OpenCode</li><li>Le jeton sera automatiquement rafraîchi</li><li>Exécutez à nouveau <code>/mystatus</code> pour consulter</li></ol><h3 id="❌-operation-incorrecte-confondre-fenetre-principale-et-fenetre-secondaire" tabindex="-1">❌ Opération incorrecte : Confondre fenêtre principale et fenêtre secondaire <a class="header-anchor" href="#❌-operation-incorrecte-confondre-fenetre-principale-et-fenetre-secondaire" aria-label="Permalink to &quot;❌ Opération incorrecte : Confondre fenêtre principale et fenêtre secondaire&quot;">​</a></h3><p><strong>Symptôme</strong> : Penser qu&#39;il n&#39;y a qu&#39;une seule fenêtre de quota, alors que la fenêtre principale est épuisée mais la secondaire fonctionne encore</p><p><strong>Cause</strong> : Les deux fenêtres sont des pools de quota indépendants.</p><p><strong>Opération correcte</strong> :</p><ul><li>Suivez le temps de réinitialisation des deux fenêtres</li><li>La fenêtre principale se réinitialise vite, la secondaire lentement</li><li>Répartissez raisonnablement l&#39;utilisation, évitez qu&#39;une fenêtre reste longtemps épuisée</li></ul><h3 id="❌-operation-incorrecte-ignorer-l-id-de-compte-d-equipe" tabindex="-1">❌ Opération incorrecte : Ignorer l&#39;ID de compte d&#39;équipe <a class="header-anchor" href="#❌-operation-incorrecte-ignorer-l-id-de-compte-d-equipe" aria-label="Permalink to &quot;❌ Opération incorrecte : Ignorer l&#39;ID de compte d&#39;équipe&quot;">​</a></h3><p><strong>Symptôme</strong> : L&#39;abonnement Team n&#39;affiche pas votre propre utilisation</p><p><strong>Cause</strong> : L&#39;abonnement Team nécessite de transmettre l&#39;ID de compte d&#39;équipe, sinon il peut interroger le compte par défaut.</p><p><strong>Opération correcte</strong> :</p><ul><li>Assurez-vous d&#39;être connecté au bon compte d&#39;équipe dans OpenCode</li><li>Le jeton contiendra automatiquement <code>chatgpt_account_id</code></li></ul><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><p>mystatus consulte les quotas en appelant l&#39;API officielle d&#39;OpenAI :</p><ul><li>Prend en charge l&#39;authentification OAuth (Plus/Team/Pro)</li><li>Affiche la fenêtre principale et la fenêtre secondaire (si elles existent)</li><li>Barre de progression visualisant le quota restant</li><li>Compte à rebours affichant le temps de réinitialisation</li><li>Détection automatique de l&#39;expiration du jeton</li></ul><h2 id="prochaine-lecon" tabindex="-1">Prochaine leçon <a class="header-anchor" href="#prochaine-lecon" aria-label="Permalink to &quot;Prochaine leçon&quot;">​</a></h2><blockquote><p>La prochaine leçon couvre <strong><a href="./../zhipu-usage/">Quota Zhipu AI et Z.ai</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Qu&#39;est-ce que la limite de token de 5 heures</li><li>Comment consulter le quota mensuel MCP</li><li>Avertissement lorsque le taux d&#39;utilisation dépasse 80%</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer l&#39;emplacement du code source</strong></summary><blockquote><p>Date de mise à jour :2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Entrée de consultation de quota OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>Appel API OpenAI</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>Formatage de sortie</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>Analyse du jeton JWT</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>Extraction de l&#39;email utilisateur</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Vérification de l&#39;expiration du jeton</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>Définition du type OpenAIAuthData</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>Constantes clés</strong> :</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code> : API officielle de consultation des quotas OpenAI</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>queryOpenAIUsage(authData)</code> : Fonction principale de consultation des quotas OpenAI</li><li><code>fetchOpenAIUsage(accessToken)</code> : Appel de l&#39;API OpenAI</li><li><code>formatOpenAIUsage(data, email)</code> : Formatage de sortie</li><li><code>parseJwt(token)</code> : Analyse du jeton JWT (implémentation non standard)</li><li><code>getEmailFromJwt(token)</code> : Extraction de l&#39;email utilisateur depuis le jeton</li><li><code>getAccountIdFromJwt(token)</code> : Extraction de l&#39;ID de compte d&#39;équipe depuis le jeton</li></ul></details>`,70)])])}const m=t(o,[["render",r]]);export{h as __pageData,m as default};
